Extensions.File:
Start-Transcript -Path "C:\Windows\Temp\DriverInstall.log"

Write-Output "==== Driver Detection Started ===="

$manufacturer = (Get-CimInstance Win32_ComputerSystem).Manufacturer
$model = (Get-CimInstance Win32_ComputerSystem).Model

Write-Output "Manufacturer: $manufacturer"
Write-Output "Model: $model"

$basePath = "C:\Drivers"

$modelClean = $model -replace '[^a-zA-Z0-9]', ''
$manufacturerClean = $manufacturer -replace '[^a-zA-Z0-9]', ''

$driverPath = "$basePath\$manufacturerClean\$modelClean"
$genericPath = "$basePath\Generic"

function Install-Drivers($path) {
    if (Test-Path $path) {
        Write-Output "Installing drivers from $path"
        pnputil /add-driver "$path\*.inf" /subdirs /install | Out-Null
    } else {
        Write-Output "Path not found: $path"
    }
}

if (Test-Path $driverPath) {
    Install-Drivers $driverPath
}
elseif (Test-Path "$basePath\$manufacturerClean") {
    Write-Output "Using manufacturer fallback"
    Install-Drivers "$basePath\$manufacturerClean"
}
elseif (Test-Path $genericPath) {
    Write-Output "Using generic drivers"
    Install-Drivers $genericPath
}
else {
    Write-Output "No drivers found"
}

Write-Output "==== Driver Install Finished ===="

Stop-Transcript

Start-Transcript -Path "C:\Windows\Temp\GPU-Install.log"

$attempts = 0
do {
    Start-Sleep 10
    $gpu = (Get-CimInstance Win32_VideoController).Name -join " "
    $attempts++
} until ($gpu -notmatch "Microsoft Basic Display" -or $attempts -ge 12)

$winget = Get-Command winget -ErrorAction SilentlyContinue

function Install-App($id) {
    if ($winget) {
        winget install -e --id $id --silent --accept-package-agreements --accept-source-agreements
    }
}

if ($gpu -match "NVIDIA") {
    Install-App "Nvidia.NvidiaApp"
}
elseif ($gpu -match "AMD") {
    Install-App "AMD.Software"
}
elseif ($gpu -match "Intel") {
    Install-App "Intel.GraphicsCommandCenter"
}

Stop-Transcript
